import React, { Fragment, useEffect, useState } from "react";
import axios from "axios";
import AdminLayout from "../admin/layout";
import { getAllCategory } from "../admin/categories/FetchApi";
import { getAllProduct } from "../admin/products/FetchApi";

const apiURL = process.env.REACT_APP_API_URL;

const Panel = ({ title, children }) => (
  <div className="bg-white shadow p-4 rounded">
    <div className="font-semibold mb-2">{title}</div>
    {children}
  </div>
);

const List = ({ items, empty }) => (
  <ul className="space-y-2 max-h-64 overflow-auto">
    {items && items.length > 0
      ? items.map((it, idx) => (
          <li key={idx} className="border-b pb-2 text-sm">
            {it}
          </li>
        ))
      : <div className="text-sm text-gray-500">{empty}</div>}
  </ul>
);

const SuperAdminDashboard = () => {
  const [hospitals, setHospitals] = useState([]);
  const [patients, setPatients] = useState([]);
  const [categories, setCategories] = useState([]);
  const [organs, setOrgans] = useState([]);
  const [analytics, setAnalytics] = useState({
    hospitals: 0,
    patients: 0,
    categories: 0,
    organs: 0,
    orders: 0,
  });

  useEffect(() => {
    const fetchAll = async () => {
      try {
        const usersRes = await axios.get(`${apiURL}/api/user/all-user`);
        const catRes = await getAllCategory();
        const prodRes = await getAllProduct();
        const ordersRes = await axios.get(`${apiURL}/api/order/get-all-orders`);

        const users = usersRes?.Users || [];
        const hosp = users.filter((u) => u.userRole === 1);
        const pats = users.filter((u) => u.userRole === 0);
        const cats = catRes?.Categories || [];
        const prods = prodRes?.Products || [];
        const orders = ordersRes?.Orders || [];

        setHospitals(hosp.map((u) => `${u.name} • ${u.email}`));
        setPatients(pats.map((u) => `${u.name} • ${u.email}`));
        setCategories(cats.map((c) => c.cName));
        setOrgans(prods.map((p) => p.pName));
        setAnalytics({
          hospitals: hosp.length,
          patients: pats.length,
          categories: cats.length,
          organs: prods.length,
          orders: orders.length || 0,
        });
      } catch (err) {
        setHospitals([]);
        setPatients([]);
        setCategories([]);
        setOrgans([]);
        setAnalytics({ hospitals: 0, patients: 0, categories: 0, organs: 0, orders: 0 });
      }
    };
    fetchAll();
  }, []);

  const Details = (
    <div className="space-y-1 text-sm">
      <div>Name: Omkar</div>
      <div>Email: itsofficialomkar@gmail.com</div>
      <div>Role: Super Admin</div>
    </div>
  );

  const Analytics = (
    <div className="grid grid-cols-2 gap-3 text-sm">
      <div className="bg-gray-100 p-3 rounded">Hospitals: {analytics.hospitals}</div>
      <div className="bg-gray-100 p-3 rounded">Patients: {analytics.patients}</div>
      <div className="bg-gray-100 p-3 rounded">Categories: {analytics.categories}</div>
      <div className="bg-gray-100 p-3 rounded">Organs: {analytics.organs}</div>
      <div className="bg-gray-100 p-3 rounded">Orders: {analytics.orders}</div>
    </div>
  );

  return (
    <Fragment>
      <div className="p-4 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        <Panel title="Details">{Details}</Panel>
        <Panel title="Hospitals">
          <List items={hospitals} empty="No hospitals" />
        </Panel>
        <Panel title="Patients">
          <List items={patients} empty="No patients" />
        </Panel>
        <Panel title="Categories">
          <List items={categories} empty="No categories" />
        </Panel>
        <Panel title="Organs">
          <List items={organs} empty="No organs" />
        </Panel>
        <Panel title="Analytics">{Analytics}</Panel>
      </div>
    </Fragment>
  );
};

const SuperAdminPage = () => {
  return (
    <Fragment>
      <AdminLayout children={<SuperAdminDashboard />} />
    </Fragment>
  );
};

export default SuperAdminPage;
